  1→import React from 'react';
  2→import { PenTool, FileText, Code, FileCode, Search, Sparkles, AlertTriangle, Feather, Shield, Bot, BookOpen, Layers, ClipboardList, Target, MessageCircle, Trophy, Radar, Code2, CheckCircle, Loader2 } from 'lucide-react';
  3→import { useTranslation } from '../i18n';
  4→import { AnalysisResult, MegaGenerationStatus } from '../types';
  5→
  6→interface GenerativeToolsProps {
  7→  onNavigate: (view: any) => void;
  8→  history?: AnalysisResult[];
  9→  megaStatus?: MegaGenerationStatus;
 10→}
 11→
 12→// IDs of tools that are pre-generable via mega-generation
 13→const PRE_GENERABLE_TOOLS: Record<string, string> = {
 14→  'robots-txt': 'robotsTxt',
 15→  'schema-org': 'schemaOrg',
 16→  'llms-txt': 'llmsTxt',
 17→  'answer-first-audit': 'answerFirstAudit',
 18→  'eeat-builder': 'eeatAudit',
 19→};
 20→// Note: llmJson is also pre-generated but shown via the llms-txt tool page
 21→
 22→interface ToolCardProps {
 23→  icon: React.ElementType;
 24→  label: string;
 25→  desc: string;
 26→  color: string;
 27→  bg: string;
 28→  onClick: () => void;
 29→  badge?: 'generating' | 'ready' | null;
 30→}
 31→
 32→const ToolCard: React.FC<ToolCardProps> = ({ icon: Icon, label, desc, color, bg, onClick, badge }) => (
 33→  <button
 34→    onClick={onClick}
 35→    className="ninja-card p-8 flex flex-col items-center justify-center gap-6 hover:bg-white/[0.04] transition-all duration-300 hover:-translate-y-2 hover:shadow-lg hover:shadow-purple-900/10 group h-full relative"
 36→  >
 37→    {badge === 'generating' && (
 38→      <span className="absolute top-3 right-3 flex items-center gap-1.5 bg-violet-500/15 text-violet-400 text-[10px] font-bold px-2.5 py-1 rounded-full border border-violet-500/20 animate-pulse">
 39→        <Loader2 size={10} className="animate-spin" /> Génération...
 40→      </span>
 41→    )}
 42→    {badge === 'ready' && (
 43→      <span className="absolute top-3 right-3 flex items-center gap-1.5 bg-emerald-500/15 text-emerald-400 text-[10px] font-bold px-2.5 py-1 rounded-full border border-emerald-500/20">
 44→        <CheckCircle size={10} /> Prêt
 45→      </span>
 46→    )}
 47→    <div className={`relative p-5 rounded-2xl ${bg} group-hover:scale-110 transition-all duration-300`}>
 48→      <Icon size={48} className={`${color} group-hover:drop-shadow-[0_0_8px_rgba(168,85,247,0.4)] transition-all duration-300`} />
 49→      <div className="absolute inset-0 rounded-2xl bg-purple-500/0 group-hover:bg-purple-500/5 transition-all duration-300" />
 50→    </div>
 51→    <div className="text-center space-y-2">
 52→      <span className="block text-xl font-bold text-gray-200 group-hover:text-white transition-colors duration-200">{label}</span>
 53→      <span className="block text-sm text-gray-500 group-hover:text-gray-400 transition-colors duration-200">{desc}</span>
 54→    </div>
 55→  </button>
 56→);
 57→
 58→const GenerativeTools: React.FC<GenerativeToolsProps> = ({ onNavigate, history, megaStatus }) => {
 59→  const { t } = useTranslation();
 60→
 61→  // Determine badge state for a given tool
 62→  const getBadge = (toolId: string): 'generating' | 'ready' | null => {
 63→    const cacheKey = PRE_GENERABLE_TOOLS[toolId];
 64→    if (!cacheKey) return null; // Not a pre-generable tool
 65→
 66→    if (megaStatus === 'generating') return 'generating';
 67→
 68→    if (megaStatus === 'completed' && history && history.length > 0) {
 69→      const preGen = history[0]?.preGenerated;
 70→      if (preGen?.status === 'completed' && (preGen as any)?.[cacheKey]) {
 71→        return 'ready';
 72→      }
 73→    }
 74→
 75→    return null;
 76→  };
 77→
 78→  const tools = [
 79→    { id: 'smc-studio', label: t.generativeTools.smcStudio, icon: PenTool, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.smcStudioDesc },
 80→    { id: 'content-writer', label: t.generativeTools.contentWriter, icon: Feather, color: 'text-violet-400', bg: 'bg-violet-500/10', desc: t.generativeTools.contentWriterDesc },
 81→    { id: 'reputation', label: t.generativeTools.reputation, icon: Shield, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.reputationDesc },
 82→    { id: 'source-of-truth', label: t.generativeTools.sourceOfTruth, icon: FileText, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.sourceOfTruthDesc },
 83→    { id: 'schema-org', label: t.generativeTools.schemaOrg, icon: Code, color: 'text-blue-400', bg: 'bg-blue-500/10', desc: t.generativeTools.schemaOrgDesc },
 84→    { id: 'robots-txt', label: t.generativeTools.robotsTxt, icon: FileCode, color: 'text-purple-300', bg: 'bg-purple-500/10', desc: t.generativeTools.robotsTxtDesc },
 85→    { id: 'bot-tracking', label: t.generativeTools.botTracking || 'Suivi Bots IA', icon: Bot, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: t.generativeTools.botTrackingDesc || 'Activation & suivi des crawlers' },
 86→    { id: 'blog-optimizer', label: t.generativeTools.blogOptimizer || 'Blog Optimiser', icon: BookOpen, color: 'text-pink-400', bg: 'bg-pink-500/10', desc: t.generativeTools.blogOptimizerDesc || 'Architecture & rédaction blog AEO' },
 87→    { id: 'ai-response-layer', label: 'AI Response Layer', icon: Layers, color: 'text-emerald-400', bg: 'bg-emerald-500/10', desc: 'Hub, Query Pages, Catalogue & Sitemap IA' },
 88→    { id: 'llms-txt', label: 'Générateur llms.txt', icon: ClipboardList, color: 'text-amber-400', bg: 'bg-amber-500/10', desc: 'Fichier llms.txt pour guider les IA sur votre marque' },
 89→    { id: 'answer-first-audit', label: 'Audit Answer-First', icon: Target, color: 'text-rose-400', bg: 'bg-rose-500/10', desc: 'Score de citabilité IA sur 6 critères AEO' },
 90→    { id: 'ai-citation-simulator', label: 'Simulateur Citation IA', icon: MessageCircle, color: 'text-sky-400', bg: 'bg-sky-500/10', desc: 'Simulez les réponses ChatGPT, Claude, Perplexity, Gemini & AI Overviews' },
 91→    { id: 'eeat-builder', label: 'E-E-A-T Builder', icon: Trophy, color: 'text-yellow-400', bg: 'bg-yellow-500/10', desc: 'Bios auteur, About Page, Trust Signals & Audit E-E-A-T' },
 92→    { id: 'ai-monitoring', label: 'Monitoring IA', icon: Radar, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: 'Tracker vos citations sur ChatGPT, Claude, Perplexity, Gemini & AI Overviews' },
 93→    { id: 'api-developer', label: 'API Developer Hub', icon: Code2, color: 'text-indigo-400', bg: 'bg-indigo-500/10', desc: 'Documentation, clés API, webhooks & SDK' },
 94→  ];
 95→
 96→  return (
 97→    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
 98→
 99→      {/* Header style Dashboard Pro */}
100→      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
101→        <div className="flex items-center gap-4">
102→          <h1 className="text-3xl font-bold text-white">{t.generativeTools.title.split(' ').slice(0, -1).join(' ')} <span className="gradient-text">{t.generativeTools.title.split(' ').slice(-1)}</span></h1>
103→          <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1 rounded-full border border-primary/20 flex items-center gap-1">
104→            <Sparkles size={12} /> {t.generativeTools.suitePro}
105→          </span>
106→        </div>
107→
108→        <div className="flex items-center gap-4 w-full md:w-auto">
109→          <div className="relative flex-1 md:flex-none">
110→            <input
111→              type="text"
112→              placeholder={t.generativeTools.searchPlaceholder}
113→              className="bg-[#111111] border border-white/[0.08] rounded-2xl py-2.5 pl-4 pr-10 text-sm text-gray-300 focus:outline-none focus:border-purple-500/50 w-full md:w-80 transition-all"
114→            />
115→            <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" />
116→          </div>
117→        </div>
118→      </div>
119→
120→      {/* Grid des Outils */}
121→      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
122→        {tools.map((tool) => (
123→            <ToolCard
124→                key={tool.id}
125→                icon={tool.icon}
126→                label={tool.label}
127→                desc={tool.desc}
128→                color={tool.color}
129→                bg={tool.bg}
130→                onClick={() => onNavigate(tool.id)}
131→                badge={getBadge(tool.id)}
132→            />
133→        ))}
134→      </div>
135→
136→      {/* Section Explicative */}
137→      <div className="ninja-card p-8">
138→        <div className="flex items-center gap-3 mb-6">
139→            <div className="p-2 bg-purple-500/10 rounded-full">
140→                <AlertTriangle size={20} className="text-yellow-400" />
141→            </div>
142→            <h3 className="text-xl font-bold text-white">{t.generativeTools.whyUse}</h3>
143→        </div>
144→
145→        <div className="grid md:grid-cols-3 gap-8">
146→            <div className="space-y-3">
147→                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.structuredContent}</h4>
148→                <p className="text-sm text-gray-500 leading-relaxed">
149→                    {t.generativeTools.structuredContentDesc}
150→                </p>
151→            </div>
152→            <div className="space-y-3">
153→                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.technicalData}</h4>
154→                <p className="text-sm text-gray-500 leading-relaxed">
155→                    {t.generativeTools.technicalDataDesc}
156→                </p>
157→            </div>
158→            <div className="space-y-3">
159→                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.sourceAuthority}</h4>
160→                <p className="text-sm text-gray-500 leading-relaxed">
161→                    {t.generativeTools.sourceAuthorityDesc}
162→                </p>
163→            </div>
164→        </div>
165→      </div>
166→
167→    </div>
168→  );
169→};
170→
171→export default GenerativeTools;
172→

  1→import React, { useState, useEffect, useCallback } from 'react';
  2→import {
  3→  ArrowLeft,
  4→  Link2,
  5→  Loader2,
  6→  CheckCircle2,
  7→  XCircle,
  8→  BarChart3,
  9→  TrendingUp,
 10→  TrendingDown,
 11→  Users,
 12→  Target,
 13→  Percent,
 14→  MousePointerClick,
 15→  Search,
 16→  Bot,
 17→  Unplug,
 18→} from 'lucide-react';
 19→import {
 20→  AreaChart,
 21→  Area,
 22→  XAxis,
 23→  YAxis,
 24→  CartesianGrid,
 25→  Tooltip,
 26→  ResponsiveContainer,
 27→  Legend,
 28→} from 'recharts';
 29→import { User } from '../types';
 30→import {
 31→  Integration,
 32→  IntegrationType,
 33→  AttributionKPI,
 34→  TrafficDataPoint,
 35→  AttributionRow,
 36→  AIQuery,
 37→} from '../types/integrations';
 38→import {
 39→  getIntegrations,
 40→  connectIntegration,
 41→  disconnectIntegration,
 42→  getAttributionKPIs,
 43→  getTrafficData,
 44→  getAttributionTable,
 45→  getAIQueries,
 46→} from '../services/integrations';
 47→
 48→interface Props {
 49→  onBack: () => void;
 50→  user: User | null;
 51→  onDeductCredits: (amount: number) => boolean;
 52→}
 53→
 54→const SOURCE_STYLES: Record<string, { color: string; bg: string; border: string }> = {
 55→  ChatGPT: { color: 'text-emerald-400', bg: 'bg-emerald-500/10', border: 'border-emerald-500/20' },
 56→  Perplexity: { color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
 57→  Claude: { color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-purple-500/20' },
 58→  Gemini: { color: 'text-amber-400', bg: 'bg-amber-500/10', border: 'border-amber-500/20' },
 59→  Copilot: { color: 'text-cyan-400', bg: 'bg-cyan-500/10', border: 'border-cyan-500/20' },
 60→  'AI Overviews': { color: 'text-rose-400', bg: 'bg-rose-500/10', border: 'border-rose-500/20' },
 61→};
 62→
 63→const CHART_COLORS: Record<string, string> = {
 64→  chatgpt: '#10b981',
 65→  perplexity: '#3b82f6',
 66→  claude: '#a855f7',
 67→  gemini: '#f59e0b',
 68→  copilot: '#06b6d4',
 69→  aiOverviews: '#f43f5e',
 70→};
 71→
 72→const Integrations: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
 73→  const [integrations, setIntegrations] = useState<Integration[]>([]);
 74→  const [connecting, setConnecting] = useState<IntegrationType | null>(null);
 75→  const [period, setPeriod] = useState<'7d' | '30d' | '90d'>('30d');
 76→  const [kpis, setKpis] = useState<AttributionKPI | null>(null);
 77→  const [trafficData, setTrafficData] = useState<TrafficDataPoint[]>([]);
 78→  const [tableData, setTableData] = useState<AttributionRow[]>([]);
 79→  const [queries, setQueries] = useState<AIQuery[]>([]);
 80→
 81→  const hasAnyConnection = integrations.some((i) => i.status === 'connected');
 82→
 83→  const refreshIntegrations = useCallback(() => {
 84→    setIntegrations(getIntegrations());
 85→  }, []);
 86→
 87→  // Load integrations on mount
 88→  useEffect(() => {
 89→    refreshIntegrations();
 90→  }, [refreshIntegrations]);
 91→
 92→  // Load dashboard data when connected and period changes
 93→  useEffect(() => {
 94→    if (!hasAnyConnection) return;
 95→    setKpis(getAttributionKPIs(period));
 96→    setTrafficData(getTrafficData(period));
 97→    setTableData(getAttributionTable());
 98→    setQueries(getAIQueries());
 99→  }, [hasAnyConnection, period]);
100→
101→  const handleConnect = async (type: IntegrationType) => {
102→    const credited = onDeductCredits(3);
103→    if (!credited) return;
104→
105→    setConnecting(type);
106→    try {
107→      await connectIntegration(type);
108→      refreshIntegrations();
109→    } catch (err) {
110→      console.error('Connection failed', err);
111→    } finally {
112→      setConnecting(null);
113→    }
114→  };
115→
116→  const handleDisconnect = (id: string) => {
117→    disconnectIntegration(id);
118→    refreshIntegrations();
119→  };
120→
121→  const ga4 = integrations.find((i) => i.type === 'ga4' && i.status === 'connected');
122→  const sc = integrations.find((i) => i.type === 'search-console' && i.status === 'connected');
123→
124→  const periodLabel = (p: string) => {
125→    if (p === '7d') return '7j';
126→    if (p === '30d') return '30j';
127→    return '90j';
128→  };
129→
130→  // ---- Render ----
131→  return (
132→    <div className="min-h-screen bg-black text-gray-100">
133→      {/* Header */}
134→      <div className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
135→        <button
136→          onClick={onBack}
137→          className="flex items-center gap-2 text-gray-400 hover:text-white transition mb-6"
138→        >
139→          <ArrowLeft size={18} />
140→          <span className="text-sm">Retour</span>
141→        </button>
142→
143→        <div className="flex items-center gap-4 mb-8">
144→          <div className="w-12 h-12 rounded-2xl bg-purple-500/10 border border-purple-500/20 flex items-center justify-center">
145→            <Link2 size={22} className="text-purple-400" />
146→          </div>
147→          <div>
148→            <h1 className="text-3xl font-bold">
149→              <span className="gradient-text">Integrations</span>
150→            </h1>
151→            <p className="text-gray-500 text-sm mt-1">
152→              Connectez vos comptes Google pour suivre le trafic IA en temps reel
153→            </p>
154→          </div>
155→          <span className="ml-auto inline-flex items-center gap-1.5 text-xs font-medium bg-purple-500/10 text-purple-300 border border-purple-500/20 rounded-full px-3 py-1">
156→            <Unplug size={13} /> 3 Gas / sync
157→          </span>
158→        </div>
159→
160→        {/* Connection cards */}
161→        <div className="grid md:grid-cols-2 gap-6 mb-10">
162→          {/* GA4 Card */}
163→          <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
164→            <div className="flex items-start gap-4">
165→              <div className="w-11 h-11 rounded-xl bg-amber-500/10 border border-amber-500/20 flex items-center justify-center shrink-0">
166→                <BarChart3 size={20} className="text-amber-400" />
167→              </div>
168→              <div className="flex-1 min-w-0">
169→                <h3 className="font-semibold text-white">Google Analytics 4</h3>
170→                <p className="text-gray-500 text-sm mt-0.5">
171→                  Importez vos donnees de trafic et conversions IA
172→                </p>
173→
174→                {ga4 ? (
175→                  <div className="mt-4 space-y-2">
176→                    <div className="flex items-center gap-2 text-sm">
177→                      <CheckCircle2 size={15} className="text-emerald-400" />
178→                      <span className="text-emerald-400 font-medium">Connecte</span>
179→                    </div>
180→                    <p className="text-xs text-gray-500 truncate">{ga4.email}</p>
181→                    <p className="text-xs text-gray-400 truncate">{ga4.property}</p>
182→                    <button
183→                      onClick={() => handleDisconnect(ga4.id)}
184→                      className="mt-3 flex items-center gap-1.5 text-xs text-red-400 hover:text-red-300 transition"
185→                    >
186→                      <XCircle size={14} /> Deconnecter
187→                    </button>
188→                  </div>
189→                ) : (
190→                  <button
191→                    onClick={() => handleConnect('ga4')}
192→                    disabled={connecting !== null}
193→                    className="mt-4 btn-gradient text-sm flex items-center gap-2 disabled:opacity-50"
194→                  >
195→                    {connecting === 'ga4' ? (
196→                      <>
197→                        <Loader2 size={15} className="animate-spin" /> Connexion...
198→                      </>
199→                    ) : (
200→                      'Connecter'
201→                    )}
202→                  </button>
203→                )}
204→              </div>
205→            </div>
206→          </div>
207→
208→          {/* Search Console Card */}
209→          <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
210→            <div className="flex items-start gap-4">
211→              <div className="w-11 h-11 rounded-xl bg-blue-500/10 border border-blue-500/20 flex items-center justify-center shrink-0">
212→                <Search size={20} className="text-blue-400" />
213→              </div>
214→              <div className="flex-1 min-w-0">
215→                <h3 className="font-semibold text-white">Google Search Console</h3>
216→                <p className="text-gray-500 text-sm mt-0.5">
217→                  Analysez vos requetes et positions liees a l'IA
218→                </p>
219→
220→                {sc ? (
221→                  <div className="mt-4 space-y-2">
222→                    <div className="flex items-center gap-2 text-sm">
223→                      <CheckCircle2 size={15} className="text-emerald-400" />
224→                      <span className="text-emerald-400 font-medium">Connecte</span>
225→                    </div>
226→                    <p className="text-xs text-gray-500 truncate">{sc.email}</p>
227→                    <p className="text-xs text-gray-400 truncate">{sc.property}</p>
228→                    <button
229→                      onClick={() => handleDisconnect(sc.id)}
230→                      className="mt-3 flex items-center gap-1.5 text-xs text-red-400 hover:text-red-300 transition"
231→                    >
232→                      <XCircle size={14} /> Deconnecter
233→                    </button>
234→                  </div>
235→                ) : (
236→                  <button
237→                    onClick={() => handleConnect('search-console')}
238→                    disabled={connecting !== null}
239→                    className="mt-4 btn-gradient text-sm flex items-center gap-2 disabled:opacity-50"
240→                  >
241→                    {connecting === 'search-console' ? (
242→                      <>
243→                        <Loader2 size={15} className="animate-spin" /> Connexion...
244→                      </>
245→                    ) : (
246→                      'Connecter'
247→                    )}
248→                  </button>
249→                )}
250→              </div>
251→            </div>
252→          </div>
253→        </div>
254→
255→        {/* Attribution Dashboard */}
256→        {hasAnyConnection && kpis && (
257→          <div className="space-y-8 animate-in">
258→            {/* Period selector */}
259→            <div className="flex items-center justify-between">
260→              <h2 className="text-xl font-bold text-white">Attribution IA</h2>
261→              <div className="flex gap-1 bg-[#111111] rounded-xl p-1 border border-white/[0.06]">
262→                {(['7d', '30d', '90d'] as const).map((p) => (
263→                  <button
264→                    key={p}
265→                    onClick={() => setPeriod(p)}
266→                    className={`px-4 py-1.5 text-sm rounded-lg font-medium transition ${
267→                      period === p
268→                        ? 'bg-purple-600 text-white'
269→                        : 'text-gray-400 hover:text-white'
270→                    }`}
271→                  >
272→                    {periodLabel(p)}
273→                  </button>
274→                ))}
275→              </div>
276→            </div>
277→
278→            {/* KPI Cards */}
279→            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
280→              <KpiCard
281→                icon={<Users size={18} className="text-purple-400" />}
282→                label="Visites IA"
283→                value={kpis.aiVisits.toLocaleString('fr-FR')}
284→              />
285→              <KpiCard
286→                icon={<Target size={18} className="text-emerald-400" />}
287→                label="Conversions IA"
288→                value={kpis.aiConversions.toLocaleString('fr-FR')}
289→              />
290→              <KpiCard
291→                icon={<Percent size={18} className="text-blue-400" />}
292→                label="Part trafic IA"
293→                value={`${kpis.aiTrafficShare}%`}
294→              />
295→              <KpiCard
296→                icon={<MousePointerClick size={18} className="text-amber-400" />}
297→                label="CTR moyen IA"
298→                value={`${kpis.aiAvgCTR}%`}
299→              />
300→            </div>
301→
302→            {/* Area Chart */}
303→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
304→              <h3 className="text-sm font-semibold text-gray-300 mb-4">
305→                Trafic IA par source
306→              </h3>
307→              <div className="h-80">
308→                <ResponsiveContainer width="100%" height="100%">
309→                  <AreaChart data={trafficData}>
310→                    <defs>
311→                      {Object.entries(CHART_COLORS).map(([key, color]) => (
312→                        <linearGradient key={key} id={`grad-${key}`} x1="0" y1="0" x2="0" y2="1">
313→                          <stop offset="0%" stopColor={color} stopOpacity={0.3} />
314→                          <stop offset="100%" stopColor={color} stopOpacity={0} />
315→                        </linearGradient>
