182→    const matchesSearch =
183→      c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
184→      c.lastMessage.toLowerCase().includes(searchQuery.toLowerCase());
185→
186→    if (filterTab === 'unread') return matchesSearch && c.unread > 0;
187→    if (filterTab === 'support') return matchesSearch && c.category === 'support';
