 15→const SourceOfTruth: React.FC<Props> = ({ onBack, history, user, onDeductCredits, savedFiles, onSaveFile }) => {
 16→  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
 17→  const [format, setFormat] = useState<'txt' | 'json'>('txt');
 18→  const [copied, setCopied] = useState(false);
