 21→  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
 22→  const [hasGenerated, setHasGenerated] = useState(false);
 23→
 24→  const GENERATION_COST = 10;
 25→
 26→  // Fonction pour simuler l'extraction de données basée sur l'URL analysée
 27→  const extractDataFromUrl = (url: string): SourceOfTruthData => {
 28→    try {
 29→        const hostname = new URL(url).hostname;
 30→        const nameParts = hostname.replace('www.', '').split('.');
 31→        const rawName = nameParts[0];
 32→        const formattedName = rawName.charAt(0).toUpperCase() + rawName.slice(1);
 33→        
 34→        return {
 35→          description: `${formattedName} est une référence dans son secteur, offrant des solutions optimisées pour les utilisateurs modernes. Notre plateforme garantit fiabilité et performance.`,
 36→          type: 'Entreprise de services numériques',
 37→          founded: '2020',
 38→          location: 'Paris, France',
 39→          services: [
 40→            { name: `Offre ${formattedName} Pro`, description: `Solution complète pour les professionnels utilisant ${formattedName}.`, category: 'B2B' },
 41→            { name: 'Support Expert', description: 'Assistance technique et accompagnement stratégique.', category: 'Service Client' }
 42→          ],
 43→          faqs: [
