 20→  data: AnalysisResult;
 21→  user: User | null;
 22→  onDeductCredits: (amount: number) => boolean;
 23→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 24→  onNavigateToAnalysis: () => void;
 25→  onNavigateToRecharge: () => void;
 26→}
